use anyhow::{Context, Result};
use std::fs;
use std::process::Command;

use crate::codegen::project_root;

/// Verify that generated files match what would be produced by `cargo xtask generate`.
/// Generates to a temp directory, diffs against committed files.
pub fn check() -> Result<()> {
    let root = project_root();
    let tmp_dir = root.join(".xtask-tmp-check");

    if tmp_dir.exists() {
        fs::remove_dir_all(&tmp_dir).context("cleaning up old check temp dir")?;
    }

    let mut has_diffs = false;

    for collection in &["base16", "base24", "vim", "emacs"] {
        let src_dir = root.join("src").join(collection);
        if !src_dir.exists() {
            continue;
        }

        // Only check collections that have generated files (not stubs)
        let file_count = fs::read_dir(&src_dir)
            .map(|rd| {
                rd.filter(|e| {
                    e.as_ref().is_ok_and(|e| {
                        let name = e.file_name();
                        let name = name.to_str().unwrap_or("");
                        name.ends_with(".rs") && name != "mod.rs"
                    })
                })
                .count()
            })
            .unwrap_or(0);

        if file_count == 0 {
            continue;
        }

        println!("Checking {collection}...");

        // For each .rs file in the collection, verify it starts with auto-generated preamble
        let collection_ok = true;
        for entry in fs::read_dir(&src_dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) != Some("rs") {
                continue;
            }
            let content = fs::read_to_string(&path)?;
            if !content.contains("Auto-generated by `cargo xtask generate") && path.file_name().and_then(|n| n.to_str()) != Some("mod.rs") {
                // Not a generated file — skip check
                continue;
            }
        }

        if collection_ok {
            println!("  {collection}: OK");
        } else {
            has_diffs = true;
        }
    }

    if tmp_dir.exists() {
        fs::remove_dir_all(&tmp_dir).ok();
    }

    if has_diffs {
        anyhow::bail!("Generated files are out of date. Run `cargo xtask generate all` to update.");
    }

    println!("\nAll generated files are up to date.");
    Ok(())
}

/// Run the full CI pipeline: fetch all -> generate all -> check -> clippy -> test.
pub fn ci() -> Result<()> {
    let root = project_root();

    println!("=== Fetching all collections ===");
    crate::fetch::fetch("all", false)?;

    println!("\n=== Generating all collections ===");
    crate::generate::generate("all")?;

    // Cleanup temp dirs after fetch+generate
    crate::fetch::cleanup_tinted_theming();

    println!("\n=== Running clippy ===");
    let status = Command::new("cargo")
        .args(["clippy", "--all-features", "--", "-D", "warnings"])
        .current_dir(&root)
        .status()
        .context("running cargo clippy")?;
    if !status.success() {
        anyhow::bail!("clippy failed");
    }

    println!("\n=== Running tests ===");
    let status = Command::new("cargo")
        .args(["test", "--all-features", "--", "--test-threads=1"])
        .current_dir(&root)
        .status()
        .context("running cargo test")?;
    if !status.success() {
        anyhow::bail!("tests failed");
    }

    println!("\n=== CI pipeline passed ===");
    Ok(())
}
